INSERT INTO `announcements` VALUES (2,'2026年518国际博物馆日特展开放','5月18日是国际博物馆日，主题为\"博物馆：联结世界的桥梁\"。登州博物馆当天全天免费开放，并在古城遗韵厅举办\"海上丝路文物特展\"，展出近年新出土的宋代沉船瓷器、明代海防火器残件等珍贵文物30余件。开放时间9:00-18:00，欢迎广大市民前来参观。','NOTICE',NULL,'PUBLISHED','2026-05-10 09:00:00','2026-05-29 18:02:34'),(3,'登州博物馆调整开放时间公告','根据季节变化，即日起登州博物馆执行夏季开放时间：5月至10月9:00-18:00（17:30停止入馆），11月至次年4月9:00-17:00（16:30停止入馆）。每周一闭馆（法定节假日除外）。入馆请携带身份证，免费参观。咨询电话：0535-5639185。','NOTICE',NULL,'PUBLISHED','2025-10-10 10:00:00','2026-05-29 18:02:34'),(4,'蓬莱区文旅局开展\"双报到公益服务集市\"活动','5月18日，蓬莱区文旅局联合登州博物馆在蓬莱阁街道海上仙街社区举办\"双报到公益服务集市\"暨国际博物馆日宣传活动。现场23家单位81名志愿者为230多位居民提供政策咨询、普法宣传、义务理发等便民服务。博物馆志愿者通过展板、科普手册、现场讲解等形式向群众介绍登州千年海防历史和馆藏精品文物。','NOTICE',NULL,'PUBLISHED','2026-05-18 14:00:00','2026-05-29 18:02:34'),(5,'元旦春节开放安排及临时闭馆公告','2026年元旦（1月1日）和春节（2月17日-23日）期间，登州博物馆正常开放，开放时间9:00-17:00。1月2日、2月24日临时闭馆一天进行设备维护和展品保养，请各位游客合理安排参观时间。','NOTICE',NULL,'PUBLISHED','2025-12-25 09:00:00','2026-05-29 18:02:34'),(6,'登州博物馆获评国家三级博物馆','经中国博物馆协会评定，登州博物馆正式获评国家三级博物馆。馆内现有藏品1794件/套，珍贵文物166件/套，设有古城遗韵、千年古港、海防重镇、文物精华、名人故里等六大展厅，系统展示登州作为\"海防重镇\"与\"中国北方海上丝绸之路最早始发港\"的辉煌历史。','NOTICE',NULL,'PUBLISHED','2026-03-15 10:00:00','2026-05-29 18:02:34'),(7,'墨拓古韵，传承文明——登州博物馆主题研学活动回顾','2026年2月8日，登州博物馆成功举办\"墨拓古韵，传承文明\"主题研学活动。本次活动面向8-12岁小学生，共招募20名学员。活动分为三个环节：首先参观博物馆馆藏文物，了解登州千年历史变迁；然后聆听拓印技艺的历史渊源与文化内涵讲解；最后每位学员亲手体验\"清版→上纸→捶打→上墨→取纸→晾干\"完整拓片制作流程，获得一份独一无二的拓片作品。活动深受学生和家长好评，登州博物馆将继续深挖馆藏资源，开发更多主题研学项目。报名电话：0535-5639185。','EDUCATION','/uploads/images/edu/edu-01.jpg','PUBLISHED','2026-02-10 09:00:00','2026-05-29 18:18:44'),(8,'探秘登州古港，解码千年文脉——海市实验小学研学纪实','蓬莱区海市实验小学五年级700余名师生走进登州博物馆，开展\"探秘登州古港，解码千年文脉\"主题研学活动。学校关工委组织志愿者在登州古港展区为学生们解读\"海上丝绸之路\"的兴衰历史，在\"名士足迹\"展区解析戚继光铠甲防护设计，现场教学生敬军礼，将爱国精神融入讲解。研学结束后举办成果展与分享会，学生提交观后感、手抄报、研学报告集等作品，成果丰硕。','EDUCATION','/uploads/images/edu/edu-02.jpg','PUBLISHED','2026-04-15 14:00:00','2026-05-29 18:18:44'),(9,'我是小小古建守护人——春假特别研学活动招募','登州博物馆将于2026年5月7日（9:00-11:00）举办\"我是小小古建守护人\"古建筑保护主题研学活动。活动地点为登州博物馆+戚继光故里小十口南街民居，面向中小学生招募20人。活动内容包括：学习中国传统古建筑基础知识，亲手参与\"古建筑复活计划\"——使用传统工具矫正木梁、古法彩绘修补窗棂。让学生在实践中感受古建之美、传承匠人精神。报名电话：0535-5639185。','EDUCATION','/uploads/images/edu/edu-03.jpg','PUBLISHED','2026-05-01 09:00:00','2026-05-29 18:18:44'),(10,'走进博物馆，争做自豪蓬莱人——第二实验小学研学活动','2026年5月，蓬莱区第二实验小学组织学生来到登州博物馆开展\"走进博物馆，争做自豪蓬莱人\"主题研学活动。学生们依次参观了六大展厅，近距离接触战国铜剑、西周青铜礼器、明清海防火器等珍贵文物。在海防重镇厅重点观摩了明代竹节炮、碗口炮等海防兵器，并探讨了文物的制作过程与使用方法。活动极大地增强了学生们的家乡荣誉感与民族自豪感。','EDUCATION','/uploads/images/edu/edu-04.jpg','PUBLISHED','2026-05-20 10:00:00','2026-05-29 18:18:44'),(11,'登州文物，拼贴胶东史——南王中学研学之旅','蓬莱区南王中学组织学生走进登州博物馆，依次参观了序厅、古城遗韵厅、千年古港厅、海防重镇厅、文物精华厅、名人故里厅共六大展厅。通过沙盘模型了解古登州城的变迁，通过滑轮、锚具、船模等文物认识海上丝绸之路的繁荣，通过铜戈、铜剑、碗口炮等兵器了解登州千年海防历史。研学将课堂教学与实地参观深度融合，让学生们\"在文物中读懂胶东\"。','EDUCATION','/uploads/images/edu/edu-05.jpg','PUBLISHED','2026-03-20 08:30:00','2026-05-29 18:18:44'),(12,'山东山大基础教育集团300余学子登州研学行','2026年5月，山东山大基础教育集团组织300余名学子赴登州开展研学之旅。行程包括：海上丝绸之路博物馆——了解古登州港繁盛景象及古代造船技术，分组协作拼接船模；蓬莱阁古建筑群——实地学习古建构件（梁、枋、斗拱、榫卯）及亭台楼阁的形制区别。登州博物馆作为起点，为学子们完整呈现了登州千年海防与海丝文化脉络。','EDUCATION','/uploads/images/edu/edu-06.jpg','PUBLISHED','2026-05-15 16:00:00','2026-05-29 18:18:44');
/*!40000 ALTER TABLE `announcements` ENABLE KEYS */;
