/*!40000 ALTER TABLE `courses` DISABLE KEYS */;
INSERT INTO `courses` VALUES (35,'墨拓古韵 传承文明——金石传拓技艺研学课程','学习中国传统金石传拓技艺，亲手制作碑刻拓片，感受千年前的\'复印技术\'。适合8-16岁青少年。','课程简介：\n传拓，是中国古代一种独特的复制技术，通过将纸覆于碑刻、铜器、砖瓦等器物上，以墨拓取其文字和纹饰。这一技艺最早可追溯至南北朝时期，至今仍是碑刻保护和金石学研究的重要手段。\n\n课程内容：\n第一课：走进登州博物馆（40分钟）\n参观古城遗韵厅和文物精华厅，重点了解馆藏碑刻文物，初步认识石碑石刻的历史文化价值。\n\n第二课：传拓文化讲堂（30分钟）\n专业老师讲解中国碑刻文化与传拓技艺的千年发展史，介绍拓印工具（拓包、墨汁、棕刷等）的使用方法。\n\n第三课：动手实践（60分钟）\n每位学员在老师指导下，使用专业工具完成一件碑刻拓片作品。完整体验：清版、上纸、捶打、上墨、取纸、晾干的全流程。\n\n第四课：作品展示（20分钟）\n学员展示自己的拓片作品，分享学习心得。优秀作品将获颁「登州小传拓师」证书。',NULL,20,0,0.00,'[{\"date\": \"每月第一个周六\", \"time\": \"9:00-11:30\", \"location\": \"登州博物馆研学教室\"}]','ACTIVE','2026-05-29 09:26:09','2026-05-29 18:10:57'),(36,'探秘千年古港——海上丝绸之路主题研学','穿越回大唐盛世，探索登州古港的辉煌岁月，了解东方海上丝绸之路的传奇故事。适合10-16岁青少年。','课程简介：\n唐代登州港是中国北方最大的对外贸易港口，被誉为东方海上丝绸之路始发港。本课程以千年古港厅为核心，带领学员追寻古代商船的航迹，揭开登州与朝鲜半岛、日本、东南亚贸易往来的神秘面纱。\n\n课程内容：\n第一课：古港探秘（40分钟）\n参观千年古港厅，近距离观察小海清淤出土的唐宋瓷器，了解这些出水文物背后的海上贸易故事。\n\n第二课：丝路寻踪（30分钟）\n学习海上丝绸之路的历史地图，认识耀州窑、龙泉窑、景德镇、高丽青瓷等不同窑口的特点，了解古代中外文化交流。\n\n第三课：我是古港小商人（40分钟）\n角色扮演互动游戏。学员分组扮演唐代商人，模拟从登州港出发，到朝鲜、日本进行贸易，用货物卡交易并记录航海日志。\n\n第四课：绘制海上丝路地图（30分钟）\n学员在空白地图上标注登州港及海上丝绸之路沿线的重要港口，创作自己的航海图。',NULL,30,0,0.00,'[{\"date\": \"每月第二个周六\", \"time\": \"9:00-11:30\", \"location\": \"登州博物馆千年古港厅\"}]','ACTIVE','2026-05-29 09:26:09','2026-05-29 18:10:57'),(37,'登州海防小卫士——古代军事文化体验课程','走进海防重镇厅，了解古代登州的海防体系，认识明代火器，体验戚家军练兵文化。适合8-14岁青少年。','课程简介：\n登州自古为「外捍朝辽、内障中原」的军事要地。明代抗倭英雄戚继光在此练兵备战，留下了丰富的海防文化遗产。本课程带领学员走进海防重镇厅，零距离接触古代兵器，感受金戈铁马的烽火岁月。\n\n课程内容：\n第一课：登州海防探秘（40分钟）\n参观海防重镇厅，认识铜戈、铜剑、碗口炮、竹节炮等古代兵器，了解蓬莱水城的防御体系。\n\n第二课：戚继光与戚家军（30分钟）\n聆听抗倭英雄戚继光的故事——封侯非我意，但愿海波平，学习戚家军的军纪与阵法。\n\n第三课：古代兵器DIY（40分钟）\n在老师指导下，用环保材料制作一个缩小版的明代碗口炮或竹节炮模型，理解火器发射的基本原理。\n\n第四课：戚家军练兵体验（30分钟）\n在户外场地模拟戚家军鸳鸯阵训练，团队协作完成阵法演练挑战，感受古代军人的纪律与勇气。',NULL,30,0,0.00,'[{\"date\": \"每月第三个周六\", \"time\": \"9:00-11:30\", \"location\": \"登州博物馆海防重镇厅\"}]','ACTIVE','2026-05-29 09:26:09','2026-05-29 18:10:57'),(38,'小小讲解员——博物馆志愿者培训课程','培养青少年讲解能力，学习登州历史文化知识，成为登州博物馆的小小文化传播使者。适合12-18岁青少年。','课程简介：\n「让文物说话，让历史发声」——本课程旨在培养一批热爱家乡文化、具备讲解能力的小小志愿者。学员将系统学习登州历史文化知识点，掌握博物馆讲解的基本技巧，并在真实场景中为观众提供讲解服务。\n\n课程内容：\n第一次课：认识博物馆（60分钟）\n参观六大展厅，了解博物馆的基本功能与登州历史文化概况。\n\n第二次课：讲解基本功（60分钟）\n学习讲解礼仪、发声技巧、肢体语言等基本技能，进行模拟讲解练习。\n\n第三次课：文物背后的故事（60分钟）\n深入学习5-10件重点文物的背景知识，练习撰写个性化的讲解词。\n\n第四次课：实战演练（90分钟）\n学员在展厅内进行真实讲解实践，由专业讲解员进行一对一指导点评。\n\n考核与认证：\n完成全部4次课程并考核通过后，学员将获得登州博物馆小小讲解员证书，并可以在周末和节假日为观众提供志愿讲解服务。',NULL,15,0,0.00,'[{\"date\": \"寒暑假集中培训（具体日期见公众号通知）\", \"time\": \"9:00-16:00\", \"location\": \"登州博物馆\"}]','ACTIVE','2026-05-29 09:26:09','2026-05-29 09:26:09'),(39,'陶艺与古瓷之美——传统陶瓷文化体验课程','从出土古瓷到拉坯体验，了解中国古代陶瓷工艺的发展演变。适合8-16岁青少年及亲子家庭。','课程简介：\n登州博物馆馆藏陶瓷文物600余件，涵盖从新石器时代陶器到清代精美瓷器的完整序列。本课程以千年古港厅和文物精华厅的陶瓷藏品为教学素材，带领学员了解泥与火的艺术，并亲手体验陶艺制作。\n\n课程内容：\n第一课：陶瓷探秘之旅（40分钟）\n参观文物精华厅和千年古港厅，以实物对照讲解陶与瓷的区别，了解中国陶瓷从原始彩陶到顶峰清瓷的演变历程。\n\n第二课：海上丝路的瓷器密码（20分钟）\n以唐代长沙窑贴花执壶、宋代耀州窑刻牡丹执壶等外销瓷为例，讲述中国瓷器如何通过登州港远销海外，改变世界对china的认知。\n\n第三课：拉坯体验（60分钟）\n在专业陶艺师的指导下，每位学员使用拉坯机亲手制作一件属于自己的陶瓷小作品。作品烧制完成后可带回留念。\n\n亲子提示：本课程欢迎亲子家庭参与，家长与孩子可以一起完成一件亲子陶艺作品。',NULL,20,0,0.00,'[{\"date\": \"每月第四个周六\", \"time\": \"9:00-12:00\", \"location\": \"登州博物馆研学教室\"}]','ACTIVE','2026-05-29 09:26:09','2026-05-29 18:10:57'),(40,'戚继光与登州——抗倭英雄主题研学','深入了解戚继光的生平事迹与军事思想，感悟\'封侯非我意，但愿海波平\'的家国情怀。适合10-18岁青少年。','课程简介：\n戚继光（1528-1588），明代著名军事家、抗倭英雄，登州（今蓬莱）人。他在这里出生、成长、练兵，最终率领戚家军转战东南沿海，平定倭患。本课程以登州博物馆名人故里厅为核心教学点，带领学员走进这位民族英雄的传奇人生。\n\n课程内容：\n第一课：少年戚继光（30分钟）\n了解戚继光的少年时代——他是如何从一个官二代成长为文武全才的。讲述戚继光「封侯非我意，但愿海波平」名句背后的故事。\n\n第二课：戚家军与抗倭战争（40分钟）\n参观海防重镇厅，了解明代抗倭战争的背景。学习戚继光的军事创新：鸳鸯阵、狼筅、虎蹲炮等。\n\n第三课：穿越时空的对话（30分钟）\n小组讨论：如果你是戚继光，面对倭寇猖獗的局面，你会如何练兵备战？各组制定作战计划并分享。\n\n第四课：写给戚继光的一封信（30分钟）\n每位学员以「写给戚将军的一封信」的形式，表达自己的学习感悟和对英雄的敬仰。优秀作品将在博物馆展示。',NULL,30,0,0.00,'[{\"date\": \"每月第一个周日\", \"time\": \"9:00-11:30\", \"location\": \"登州博物馆名人故里厅\"}]','ACTIVE','2026-05-29 09:26:09','2026-05-29 18:10:57');
