/*!40000 ALTER TABLE `relics` DISABLE KEYS */;
INSERT INTO `relics` VALUES (292,'宋耀州窑刻牡丹纹执壶','胎薄质细，腹部刻团花牡丹纹，釉色青中泛黄。喇叭口，长流，曲柄，造型优美。蓬莱水城小海清淤出土，是宋代耀州窑刻花瓷器的代表作。此壶为当时登州港对外出口的外销瓷品种之一。','宋代','瓷器','/uploads/images/relics/song-yao-zhou-yao-ke-mu-dan-wen-zhi-hu.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:29:59'),(293,'唐长沙窑黄釉褐彩贴花执壶','釉下彩装饰，典型的长沙窑外销瓷。壶身贴花纹饰融合了中西亚艺术元素，壶腹贴椰枣纹模印贴花。蓬莱水城小海清淤出土，见证了大唐海上丝绸之路的繁荣与东西方文化交流。','唐代','瓷器','/uploads/images/relics/tang-chang-sha-yao-huang-you-he-cai-tie-hua-zhi-hu.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:29:59'),(300,'战国“安阳之法化”刀币','战国“安阳之法化”刀币，战国时期时期文物。质地为铜。钱币虽小，却记录了一个王朝的经济脉搏，是研究古代商品经济的重要实物资料。经鉴定为国家二级文物，具有重要的历史价值和艺术价值。','战国时期','钱币','/uploads/images/relics/zhan-guo-an-yang-zhi-fa-hua-dao-bi.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(301,'西周兽面纹铜鼎','西周兽面纹铜鼎，西周时期文物。质地为铜。青铜的沉稳光泽中，凝聚着古人的智慧与匠心，是青铜文明的珍贵遗存。经鉴定为国家二级文物，具有重要的历史价值和艺术价值。','西周','铜器','/uploads/images/relics/xi-zhou-shou-mian-wen-tong-ding.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(302,'汉“王翁主尉”铜印章','汉“王翁主尉”铜印章，汉时期文物。质地为铜。方寸之间凝聚着权力与信用的象征。它虽无华丽的外表，却是解读历史不可或缺的密码。','汉','玺印符牌','/uploads/images/relics/han-wang-weng-zhu-wei-tong-yin-zhang.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(303,'东汉画像刻石','东汉画像刻石，东汉时期文物。质地为石。石上刻痕穿越千年时光，默默诉说着古老的故事。经鉴定为国家三级文物，具有重要的历史价值和艺术价值。','东汉','石器·石刻·砖瓦','/uploads/images/relics/dong-han-hua-xiang-ke-shi.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(304,'中华民国“徐克吉”石印章','中华民国“徐克吉”石印章，中华民国时期文物。质地为石。方寸之间凝聚着权力与信用的象征。它虽无华丽的外表，却是解读历史不可或缺的密码。','中华民国','玺印符牌','/uploads/images/relics/zhong-hua-min-guo-xu-ke-ji-shi-yin-zhang.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(305,'清仿“右卢淳车羽工鈢”铜印章','清仿“右卢淳车羽工鈢”铜印章，清时期文物。质地为铜。方寸之间凝聚着权力与信用的象征。它虽无华丽的外表，却是解读历史不可或缺的密码。','清','玺印符牌','/uploads/images/relics/qing-fang-you-lu-chun-che-yu-gong-xi-tong-yin-zhang.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(306,'元绿釉瓜棱纹陶罐','元绿釉瓜棱纹陶罐，元时期文物。质地为陶。火与土的第一次亲密接触，陶器虽质朴，却凝聚了先民最本真的智慧。经鉴定为国家三级文物，具有重要的历史价值和艺术价值。','元','陶器','/uploads/images/relics/yuan-lv-you-gua-leng-wen-tao-guan.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(307,'鲸鱼下颌骨（标本）','鲸鱼下颌骨（标本），年代不详时期文物。质地为骨角牙。大自然是最好的记录者，为地球生命演化留下了珍贵的档案。它虽无华丽的外表，却是解读历史不可或缺的密码。','年代不详','标本·化石','/uploads/images/relics/jing-yu-xia-he-gu-biao-ben.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(308,'北宋铜钱（样板）','北宋铜钱（样板），北宋时期文物。质地为铜。钱币虽小，却记录了一个王朝的经济脉搏，是研究古代商品经济的重要实物资料。它虽无华丽的外表，却是解读历史不可或缺的密码。','北宋','钱币','/uploads/images/relics/bei-song-tong-qian-yang-ban.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(309,'明龙泉窑豆青印花盘','明龙泉窑豆青印花盘，明时期文物。质地为瓷。泥与火的艺术在此化作永恒的美丽，体现了中国古代陶瓷工艺的高超水平。经鉴定为国家二级文物，具有重要的历史价值和艺术价值。','明','瓷器','/uploads/images/relics/ming-long-quan-yao-dou-qing-yin-hua-pan.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(310,'清双龙钮钟','清双龙钮钟，清时期文物。质地为铜。这件文物承载着丰富的历史记忆，让我们得以一窥先民的智慧与匠心。它虽无华丽的外表，却是解读历史不可或缺的密码。','清','乐器·法器','/uploads/images/relics/qing-shuang-long-niu-zhong-F0788C.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 10:36:01'),(311,'1984年蓬莱水城清淤出土鹿角（标本）','1984年蓬莱水城清淤出土鹿角（标本），年代不详时期文物。质地为骨角牙。大自然是最好的记录者，为地球生命演化留下了珍贵的档案。它虽无华丽的外表，却是解读历史不可或缺的密码。','年代不详','标本·化石','/uploads/images/relics/nian-peng-lai-shui-cheng-qing-yu-chu-tu-lu-jiao-biao-ben-5B883C.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 10:36:01'),(312,'清铁炮','清铁炮，清时期文物。质地为铁。冰冷的钢铁背后凝结着烽火岁月的记忆，见证了古代军事技术的发展。经鉴定为国家三级文物，具有重要的历史价值和艺术价值。','清','武器','/uploads/images/relics/qing-tie-pao.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(313,'1962年俞剑华蓬莱阁图轴','1962年俞剑华蓬莱阁图轴，公元20世纪时期文物。质地为纸。一笔一画间流淌着千年的文脉与气韵。它虽无华丽的外表，却是解读历史不可或缺的密码。','公元20世纪','书法·绘画','/uploads/images/relics/nian-yu-jian-hua-peng-lai-ge-tu-zhou.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(314,'汉几何纹磨牙花岗岩石磨','汉几何纹磨牙花岗岩石磨，汉时期文物。质地为石。石上刻痕穿越千年时光，默默诉说着古老的故事。经鉴定为国家二级文物，具有重要的历史价值和艺术价值。','汉','石器·石刻·砖瓦','/uploads/images/relics/han-ji-he-wen-mo-ya-hua-gang-yan-shi-mo.jpg',NULL,NULL,'2026-05-29 09:26:09','2026-05-29 09:26:09'),(315,'中华民国彩绘官帽盒（资料）','中华民国彩绘官帽盒（资料），中华民国时期文物。质地为木。这件文物承载着丰富的历史记忆，让我们得以一窥先民的智慧与匠心。它虽无华丽